-- ============================================================================
-- Vcore — Carga del catálogo base (26 productos)
-- Pegá TODO esto en: Supabase -> SQL Editor -> New query -> Run
-- Idempotente: si un producto ya existe, lo actualiza (no duplica).
-- ============================================================================
on conflict (id) do update set
  name = excluded.name, sub = excluded.sub, category = excluded.category,
  badge = excluded.badge, blurb = excluded.blurb, tone = excluded.tone,
  photo = excluded.photo, variants = excluded.variants, price = excluded.price,
  rating = excluded.rating, reviews = excluded.reviews,
  visible = excluded.visible, featured = excluded.featured, sort = excluded.sort;
